final:
module lfsr_8bit(
   input                clk,
   input                rst_n,

   output reg [7:0]     obf_Q
);
    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) obf_Q <= 8'b00000001;
        else begin
            obf_Q <= {obf_Q[6:0], obf_Q[7] ^ obf_Q[5] ^ obf_Q[4] ^ obf_Q[3]};
        end
    end
endmodule
